import { Data_UsableItem, Enemy_Action, ItemEffect } from '../../../../../rmmz/rpg';
import { Rmmz_Action_Damage } from './damage';
import { Rmmz_Action_ItemEffect } from './itemEffect';
import { Rmmz_Action_Target } from './target';
import { Rmmz_Action_DamageTrait, Rmmz_Action_TargetTrait } from './trait';
export interface Rmmz_ActionBase<Battler, Team> extends Rmmz_Action_ItemEffect<Battler>, Rmmz_Action_DamageTrait, Rmmz_Action_TargetTrait, Rmmz_Action_Damage<Battler>, Rmmz_Action_Target<Battler, Team> {
    clear(): void;
    friendsUnit(): Team;
    opponentsUnit(): Team;
    setEnemyAction(action: Enemy_Action): void;
    setAttack(): void;
    setGuard(): void;
    setSkill(skillId: number): void;
    setItem(itemId: number): void;
    setItemObject(object: Data_UsableItem): void;
    setTarget(targetIndex: number): void;
    item(): Data_UsableItem | null;
    isSkill(): boolean;
    isItem(): boolean;
    numRepeats(): number;
    decideRandomTarget(): void;
    setConfusion(): void;
    prepare(): void;
    isValid(): boolean;
    speed(): number;
    evaluate(): number;
    itemTargetCandidates(): number;
    evaluateWithTarget(target: Battler): number;
    testApply(target: Battler): boolean;
    testLifeAndDeath(target: Battler): boolean;
    hasItemAnyValidEffects(target: Battler): boolean;
    testItemEffect(target: Battler, effect: ItemEffect): boolean;
    itemCnt(target: Battler): number;
    itemMrf(target: Battler): number;
    itemHit(battler: Battler): number;
    itemEva(target: Battler): number;
    itemCri(target: Battler): number;
}
